external_knowledge:
; A salesperson's performance is often evaluated based on their recent sales; 
; The top three most recent sales provide insight into a salesperson's current performance; 
; Service records can indicate the condition and maintenance history of a vehicle.

sql:
SELECT service_type
FROM service_records
WHERE vehicle_id = 1 AND service_date >= '2023-09-01';

SELECT MAX(total_revenue) AS highest_revenue
FROM (
    SELECT salesperson_id, SUM(sale_price) AS total_revenue
    FROM sales
    GROUP BY salesperson_id
) AS revenue_per_salesperson;

SELECT sale_id
FROM sales
ORDER BY sale_date DESC;
